/**
 * Bundled OpenType MATH font for the formula plugin (opt-in, zero-dependency).
 *
 * "Notectl Math" is a subset of Noto Sans Math (Copyright 2022 Google LLC),
 * licensed under the SIL Open Font License 1.1. Per the OFL, this Modified
 * Version does NOT carry the Reserved Font Name "Noto Sans Math" (its internal
 * family name is "Notectl Math"). See THIRD-PARTY-NOTICES.md.
 *
 * Chromium renders MathML stretchy constructs (matrix brackets, large
 * integrals/roots) incorrectly without an OpenType MATH font; applying this
 * font via `font-family` fixes that (verified in a real-browser spike). It is
 * a self-hosted font ASSET, not an npm dependency — the single-runtime-dependency
 * promise (only `dompurify`) is unaffected.
 *
 * Import from '@notectl/core/fonts' and pass to the plugin:
 *   import { NOTECTL_MATH_FONT } from '@notectl/core/fonts';
 *   new FormulaPlugin({ mathFont: NOTECTL_MATH_FONT });
 *
 * The base64 payload keeps it out of the main bundle (tree-shakeable; only the
 * ./fonts entry references it).
 */

import type { FontDefinition } from '../font/FontPlugin.js';

const NOTECTL_MATH_WOFF2_DATA: string =
	'data:font/woff2;base64,';

/** Subset of Noto Sans Math as a self-hosted WOFF2 `FontDefinition` (family: "Notectl Math"). */
export const NOTECTL_MATH_FONT: FontDefinition = {
	name: 'Notectl Math',
	family: "'Notectl Math', math",
	category: 'serif',
	fontFaces: [
		{
			src: `url(${NOTECTL_MATH_WOFF2_DATA}) format('woff2')`,
			weight: '400',
			style: 'normal',
			display: 'swap',
		},
	],
};
